"""
Dish Dataset — the 14 flavor dimensions and the 40-dish catalog.

Every other module imports DIMENSIONS/DIM_LABELS from here, so this is the
single source of truth for dish/vector shape.

Each dish also carries dietary/health metadata used by dietary_filter.py:
- is_vegetarian/is_vegan/is_gluten_free/is_dairy_free/allergens are
  hand-authored real-world facts about the dish — they cannot be derived
  from the flavor vector, since e.g. "how much a dish tastes sweet" says
  nothing about whether it contains dairy.
- sugar_level/fat_level/sodium_level (0-10, same convention as the flavor
  vector) approximate nutrition for the soft health-penalty path. They start
  from a heuristic correlated with existing flavor dims (sugar~sweetness,
  fat~richness+crunch, sodium~saltiness+umami) with manual overrides where
  that heuristic clearly under/over-shoots (e.g. desserts get a high
  sugar_level regardless of their taste-perception sweetness score).

This is a prototype demo dataset, not verified nutrition data. One judgment
call worth flagging: this targets the Indian market (Zomato RFP), where
standard veg/non-veg classification treats egg as non-vegetarian, but
Chocolate Brownie/Tiramisu/Caesar Salad dressing are treated here as their
common Indian eggless variants (is_vegetarian=True, no "eggs" allergen tag).
"""

# Canonical dimension order. Every flavor vector (dish or target) is a dict
# keyed by these 14 strings — order here only matters for vec(...) below.
DIMENSIONS = [
    "spice", "acidity", "richness", "warmth", "crunch", "umami", "sweetness",
    "bitterness", "saltiness", "freshness", "moisture", "aroma", "chewiness",
    "temp_contrast",
]

DIM_LABELS = {
    "spice": "Spice",
    "acidity": "Acidity",
    "richness": "Richness",
    "warmth": "Warmth",
    "crunch": "Crunch",
    "umami": "Umami",
    "sweetness": "Sweetness",
    "bitterness": "Bitterness",
    "saltiness": "Saltiness",
    "freshness": "Freshness",
    "moisture": "Juiciness",
    "aroma": "Aroma",
    "chewiness": "Chewiness",
    "temp_contrast": "Temp Contrast",
}


def vec(*values):
    """Builds a flavor-vector dict from 14 positional 0-10 scores, in DIMENSIONS order."""
    return dict(zip(DIMENSIONS, values))


def diet(is_vegetarian, is_vegan, is_gluten_free, is_dairy_free, allergens, sugar_level, fat_level, sodium_level):
    """Builds the dietary/health metadata dict shared by every dish below."""
    return {
        "is_vegetarian": is_vegetarian,
        "is_vegan": is_vegan,
        "is_gluten_free": is_gluten_free,
        "is_dairy_free": is_dairy_free,
        "allergens": allergens,
        "sugar_level": sugar_level,
        "fat_level": fat_level,
        "sodium_level": sodium_level,
    }


